window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2006>1>a>i","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Mention one structural similarity among specimens A. B, C, D, and E","images":[],"marking_scheme":"-They all have chloroplast containing chlorophyll   -They are all green with leaf-like structure.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>1>a>ii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State the observable reproductive structure in each of specimens A, B, C, D, and E","images":[],"marking_scheme":"Specimen A (grass) has flowers (spike) and rhizome for reproduction   Specimen B (Fern) has sori and rhizome for reproduction   Specimen C (water leaf) has flowers (stem) for reproduction  Specimen D (moss) has capsule for reproduction   -Specimen E (Delonix region) has Flowers for reproduction","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>1>a>iii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"iii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"In a tabular form list eight structural differences between specimens A, and C","images":[],"marking_scheme":"Specimen A (grass)Specimen C (water leaf)Leaves are narrow or elongatedLeaves are broadIt has fibrous root systemIt has tap root systemLeaves have parallel venationLeaves have (Net) reticulate venationStem and leaves are non succulentStem and leaves are succulentLeaf sheath present Petiole presentpointed leaf tipBroad or indented leaf tipFlowers are in inflorescenceFlowers are solitary.Flowers are small and tinyFlowers are largeFlowers are dullFlowers have bright coloursHairs present in the bodyHairs absentAbsence of branchesPresence of branches","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2006>1>b>i","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Make a drawing 8cm to 10cm long, of the shoot system of specimen C and label fully","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of shoot system of specimen C/water leaf/Talinum triangluare","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>1>b>ii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Arrange specimens A, B, C, D, and E in order of complexity from the simplest to the most complex.","images":[],"marking_scheme":"(D) Moss \u2192 (B) Fern \u2192 (A) Grass \u2192 (C) Water leaf \u2192 (E) Delonix regia","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>2>a>i","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES","question":"Mention the stage of development of specimens F, G, and H","images":[],"marking_scheme":"specimens F-Egg   G-Larva and   H-Adult","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>2>a>ii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"State the trophic level of specimen H","images":[],"marking_scheme":"Consumer","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2006>2>a>iii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"iii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : LIFE CYCLES","question":"State where each of specimens F, G, and H can be found in nature","images":[],"marking_scheme":"F -in the ground  G - rotting fruits, vegetables and animal carcasses  H - Fields, pastures, garden and grasslands","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>2>b>i","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"State two ways each in which specimens G and H are of economic importance","images":[],"marking_scheme":"specimens H  -It is a pest of plants destroying crops and   -causing reduction in crop yield   specimens G   -It serves as source of protein. It transmits plant pathogens.   -It is used as fishing baits","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>2>b>ii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"State the observable adaptive features of each of specimens F, G, and H to their habitats","images":[],"marking_scheme":"Specimen F (Egg case)   -It has hard egg case which protects it from mechanical and chemical injury   -The hard egg case also prevents desiccation and maintains suitable internal temperature  -The Dark brown colour makes it difficult to be see in the dark  -This is a form of camouflage.  -It has narrow shape which enables it to fit into crevices  (b) Specimen G (Maggot)  -it has anterior hook for tearing food and for movement.  -The soft body allows for wriggling movements  -It has hooks at the tip of the pad on the ventral surface for crawling movement   -It has spiracles for gaseous exchange.    (c) Specimen H (Grasshopper)  -It has adaptive colouration, which blends with the environment (Vegetation)   -It has powerful and long hind limbs for hopping away from danger.   -It has wings for flying to avoid predators and movement from one plant to the other for food   -It has strong mandibles as mouth parts for feeding on vegetation.   -It has hardened fore wings to protect the membranous hind wings usual for flying  -It has long antennae, which are sensitive to touch It has spiracles for gaseous exchange  -It has a pair of compound eyes for wider vision","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>2>b>iii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Classify specimen F into its Kingdom, phylum and Class","images":[],"marking_scheme":"Kingdom- Animalia  Phylum- Arthropoda  Class- Insecta","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>3>a>i","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Specimen P is a bean seedling and specimen Q is a maize seedling, carefully examine the specimens and state the type of germination of each giving reasons","images":[],"marking_scheme":"Specimen P (Bean seedling). The type of germination is epigeal in which the cotyledons appeared above the ground,     Specimen Q (Maize seedling). The type of germination is hypogeal in which the cotyledon remained below the ground","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>3>a>ii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"List four conditions necessary for germination","images":[],"marking_scheme":"-Water or Moisture  -Warmth or suitable temperature.  -Air or oxygen  -Viable seeds","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>3>a>iii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Make a drawing 8-10cm long of specimen P and label fully","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of Specimen P/Bean seedling","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2006>3>a>iv","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"iv","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State one function each of any four of the labelled parts","images":[],"marking_scheme":"The leave carry out photosynthesis to manufacture food for the plant.  Epicotyl or Hypocotyl: holds leaf above the ground to receive sunlight and transports water and mineral salts to the leaves.  Secondary Root Anchors plant to the soil and absorb water and mineral salts.  Cotyledon: provides food for developing plant i.e. seedling.  Primary Root: absorbs water and nutrients to the plant","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2006>3>b>i","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Give the agricultural classification of specimens P and Q","images":[],"marking_scheme":"Specimen P is a legume.   Specimen Q is a cereal.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>3>b>ii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Where is food stored in specimens P and Q?","images":[],"marking_scheme":"Specimen P (Bean seedling) stores food in the cotyledon   Specimen Q (Maize seedling) stores food in the Endosperm","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2006>3>b>iii","subject":"Biology Practical","year":"2006","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State how specimen P is of economic importance","images":[],"marking_scheme":"-It serves as a source of protein in food  -It serves as cover crops to prevent erosion  -It provides organic manure to the soil  -It serves as fodder crops for farm animals  -It is used in crop rotation for maintaining soil fertility  -It enhances the fertility of the soil through nitrogen fixation by housing nitrogen fixing bacteria in their root nodules that converts atmospheric nitrogen to nitrates","marks":"1","difficulty":"2"}];